  wd:Q511040 wdt:P764 ?season .
  ?season wdt:P31 wd:Q7286315 .
  {
    ?season wdt:P1612 wd:Q264129 ; wdt:P1613 ?opponent
  } UNION {
    ?season wdt:P1613 wd:Q264129 ; wdt:P1612 ?opponent
  }
}

SELECT DISTINCT STR(YEAR(?horrorRelease)) AS ?releaseYear
WHERE {
  ?film wdt:P31 wd:Q11424;
         wdt:P577 ?releaseDate;
         wdt:P2142 ?boxOffice;
         wdt:P272 ?studio.
  ?boxOffice wikibase:quantityAmount ?boxValue.
  FILTER(STR(?releaseDate) >= "1957-01-01" && STR(?releaseDate) <= "1957-12-31")
  FILTER(?boxValue >= 14000000 && ?boxValue <= 16000000)

  ?horrorFilm wdt:P272 ?studio;
             wdt:P136 wd:Q43919;
             wdt:P577 ?horrorRelease.
  FILTER(STR(?horrorRelease) >= "1940-01-01" && STR(?horrorRelease) <= "1970-12-31")
} ORDER BY ?releaseYear

SELECT ?area WHERE {
  wd:Q38 wdt:P2046 ?area
}

SELECT ?mallLabel WHERE {
  wd:Q1473 wdt:P31 wd:Q515 ; wdt:P17 wd:Q162 ; wdt:P1082 ?population .
  ?mall wdt:P31 wd:Q4155622 ; wdt:P131 wd:Q1473 .
  ?mall rdfs:label ?mallLabel .
  FILTER(LANG(?mallLabel) = 'en')
  FILTER NOT EXISTS {
    ?mall wdt:P131 ?otherCity
  }
}

SELECT ?label WHERE {
  wd:Q917861 wdt:P264 ?label
}

SELECT ?capacity WHERE {
  wd:Q517268 wdt:P1083 ?capacity
}

SELECT(COUNT(DISTINCT ?state) AS ?count) WHERE {
  wd:Q1055811 wdt:P150 ?station .
  ?station wdt:P276 ?city .
  ?city wdt:P131 ?state .
}

SELECT ?player ?birthYear WHERE {
  ?player wdt:P31 wd:Q5 ; p:P1363 ?statement ; ps:P1363 ?goals ; pq:P2044 wd:Q2109818 ; wdt:P569 ?birthDate ;
  BIND(YEAR(?birthDate) AS ?birthYear)
}
ORDER BY DESC(?goals)
LIMIT 1

SELECT ?province WHERE {
  ?province wdt:P302 wd:Q37274 ; wdt:P131 wd:Q44798 .
}

SELECT ?medal WHERE {
  ?result wdt:P1443 "8:37.51" ; wdt:P1547 ?medal ; wdt:P1544 wd:Q55244942 .
  wd:Q55244942 wdt:P153 wd:Q17299929 .
}

SELECT DISTINCT ?songLabel WHERE {
  ?song wdt:P175 wd:Q313578 .
  ?song rdfs:label ?songLabel .
  FILTER (lang(?songLabel) = "en")
  FILTER (STRBEFORE(STR(?songLabel), " (")) = "Ice Ice Baby")
}
